            this.Load += (s, e) => 
            {
                EnableAutoStartup();
                CheckAndHideIfConnected();
            };
        }

        private void ShowFromTray()
        {
            this.WindowState = FormWindowState.Normal;
            this.ShowInTaskbar = true;
            notifyIcon.Visible = false;
            this.Activate();
        }

        private void EnableAutoStartup()
        {
            try
            {
                // Check if already enabled
                using (var key = Microsoft.Win32.Registry.CurrentUser.OpenSubKey(@"Software\Microsoft\Windows\CurrentVersion\Run", true))
                {
                    if (key != null)
                    {
                        object existingValue = key.GetValue("FileserverDriveManager");
                        if (existingValue == null)
                        {
                            // Not enabled yet - add it
                            string exePath = System.Reflection.Assembly.GetExecutingAssembly().Location;
                            key.SetValue("FileserverDriveManager", exePath);
                            Log("Auto-startup enabled");
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Log("Error enabling auto-startup: " + ex.Message);
            }
        }

        private void CheckAndHideIfConnected()
        {
            // Wait a moment for Tailscale to initialize
            System.Threading.Thread.Sleep(2000);
            
            // Check if this is first launch (no drives configured)
            if (drives.Count == 0)
            {
                Log("First launch - showing app for setup");
                return;  // Show the app
            }
            
            // Check if all drives are mapped
            bool allConnected = drives.All(d => IsDriveMounted(d.DriveLetter));
            
            if (allConnected)
            {
                // All drives connected - minimize to system tray
                this.WindowState = FormWindowState.Minimized;
                this.ShowInTaskbar = false;
                notifyIcon.Visible = true;
                Log("All drives connected - app minimized to tray");
            }
            else
            {
                // Some drives disconnected - show the app normally
                Log("Some drives disconnected - app visible");
            }
        }

        private void LoadDrives()
        {
            // Load saved drives from settings
            LoadSavedSettings();
        }

