        private void UpdateNetworkInfo()
        {
            try
            {
                string networkInfo = GetNetworkInfo();
                if (networkLabel != null && networkLabel.InvokeRequired)
                {
                    networkLabel.Invoke(new Action(() =>
                    {
                        networkLabel.Text = networkInfo;
                    }));
                }
                else if (networkLabel != null)
                {
                    networkLabel.Text = networkInfo;
                }
            }
            catch
            {
                // Silently fail
            }
        }

        private string GetNetworkInfo()
        {
            try
            {
                // Get all network interfaces
                NetworkInterface[] interfaces = NetworkInterface.GetAllNetworkInterfaces();
                List<string> networkAddresses = new List<string>();

                foreach (NetworkInterface ni in interfaces)
                {
                    // Skip loopback and non-operational interfaces
                    if (ni.NetworkInterfaceType == NetworkInterfaceType.Loopback || ni.OperationalStatus != OperationalStatus.Up)
                        continue;

                    // Get IPv4 addresses
                    if (ni.GetIPProperties().UnicastAddresses.Count > 0)
                    {
                        foreach (UnicastIPAddressInformation ip in ni.GetIPProperties().UnicastAddresses)
                        {
                            if (ip.Address.AddressFamily == System.Net.Sockets.AddressFamily.InterNetwork)
                            {
                                // Skip Tailscale IPs (100.x.x.x)
                                if (ip.Address.ToString().StartsWith("100."))
                                    continue;

                                string type = ni.NetworkInterfaceType == NetworkInterfaceType.Wireless80211 ? "WiFi" : "LAN";
                                networkAddresses.Add($"{ip.Address}({type})");
                            }
                        }
                    }
                }

                if (networkAddresses.Count > 0)
                {
                    return "Network: " + string.Join(" | ", networkAddresses);
                }
                else
                {
                    return "Network: Disconnected";
                }
            }
            catch
            {
                return "Network: Error";
            }
        }

        private void AuthenticateButton_Click(object sender, EventArgs e)
        {
            string username = usernameBox.Text.Trim();
            string password = passwordBox.Text.Trim();

            if (string.IsNullOrEmpty(username) || string.IsNullOrEmpty(password))
            {
                statusLabel.Text = "Enter username and password first";
                return;
            }

            try
            {
                isAuthenticating = true;  // Prevent RefreshStatus from updating
                statusLabel.Text = "Authenticating...";
                
                // Get available shares from fileserver using SMB enumeration
                GetAvailableShares(username, password);
                
                // Populate available drive letters (A-Z minus those already used)
                PopulateAvailableDriveLetters();
                
                // Enable Add/Remove buttons on successful authentication
                addDriveButton.Enabled = true;
                removeDriveButton.Enabled = true;
                addDriveButton.BackColor = Color.FromArgb(21, 101, 200);  // Bright blue
                removeDriveButton.BackColor = Color.FromArgb(229, 57, 53);  // Bright red
                
                statusLabel.Text = "Authentication successful - select shares";
                Log("Authentication successful");
            }
            catch (Exception ex)
            {
                statusLabel.Text = "Authentication failed";
                addDriveButton.Enabled = false;
                removeDriveButton.Enabled = false;
                addDriveButton.BackColor = Color.FromArgb(150, 150, 150);  // Grey
                removeDriveButton.BackColor = Color.FromArgb(150, 150, 150);  // Grey
                Log("Authentication error: " + ex.Message);
                MessageBox.Show("Failed to authenticate: " + ex.Message, "Error");
            }
            finally
            {
                isAuthenticating = false;  // Re-enable RefreshStatus
            }
        }

        private void GetAvailableShares(string username, string password)
        {
            // List of known shares from fileserver
            string[] knownShares = { "DynaBackup", "General", "Thomas", "Estelle", "Daniela", "Archives", "Proxmox", "IT", "Media", "SpinData" };
            
            shareNameBox.Items.Clear();
            
            int accessibleCount = 0;
            foreach (string share in knownShares)
            {
                statusLabel.Text = $"Testing share access... ({accessibleCount + 1}/{knownShares.Length})";
                Application.DoEvents();  // Update UI
                
                // Quick test - try to mount and unmount each share
                if (TestShareAccess(username, password, share))
                {
                    shareNameBox.Items.Add(share);
                    Log($"Share accessible: {share}");
                    accessibleCount++;
                }
                else
                {
                    Log($"Share not accessible: {share}");
                }
            }
            
            if (accessibleCount == 0)
            {
                throw new Exception("User has no access to any shares on fileserver. Please check username/password.");
            }
            
            statusLabel.Text = $"Found {accessibleCount} accessible shares";
        }

        private bool TestShareAccess(string username, string password, string shareName)
        {
            try
            {
                string sharePath = $"\\\\{fileserverIP}\\{shareName}";
                
                // Try to mount the share temporarily
                string cmd = $"net use * \"{sharePath}\" {password} /user:{username} /persistent:no";
                
                ProcessStartInfo psi = new ProcessStartInfo("cmd.exe", $"/c {cmd}")
                {
                    UseShellExecute = false,
                    RedirectStandardOutput = true,
                    RedirectStandardError = true,
                    CreateNoWindow = true
                };
                
                using (Process p = Process.Start(psi))
                {
                    // Wait max 3 seconds per share
                    bool completed = p.WaitForExit(3000);
                    
                    if (!completed)
                    {
                        // Timeout
                        try { p.Kill(); }
                        catch { }
                        return false;
                    }
                    
                    // Check if successful (exit code 0)
                    if (p.ExitCode == 0)
                    {
                        // Disconnect immediately
                        try
                        {
                            ProcessStartInfo disconnectPsi = new ProcessStartInfo("cmd.exe", "/c net use * /delete /yes")
                            {
                                UseShellExecute = false,
                                RedirectStandardOutput = true,
                                CreateNoWindow = true
                            };
                            using (Process dp = Process.Start(disconnectPsi))
                            {
                                dp.WaitForExit(1000);
                            }
                        }
                        catch { }
                        
                        return true;
                    }
                    
                    return false;
                }
            }
            catch (Exception ex)
            {
                Log($"Error testing share {shareName}: {ex.Message}");
                return false;
            }
        }

        private void PopulateAvailableDriveLetters()
        {
            driveLetterBox.Items.Clear();
            
            // Get already used drive letters
            HashSet<string> usedLetters = new HashSet<string>();
            foreach (var drive in drives)
            {
                usedLetters.Add(drive.DriveLetter.ToUpper().Replace(":", ""));
            }
            
            // Add available letters (skip C: for system drive, and A:, B: for floppy)
            for (char c = 'D'; c <= 'Z'; c++)
            {
                string letter = c.ToString();
                if (!usedLetters.Contains(letter))
                {
                    driveLetterBox.Items.Add(letter);
                }
            }
            
            // Select first available
            if (driveLetterBox.Items.Count > 0)
            {
                driveLetterBox.SelectedIndex = 0;
            }
        }

        private void AddDriveButton_Click(object sender, EventArgs e)
        {
            if (drives.Count >= 5)
            {
                MessageBox.Show("Maximum 5 drives allowed");
                return;
            }

            string letter = driveLetterBox.SelectedItem?.ToString() ?? "";
            string share = shareNameBox.SelectedItem?.ToString() ?? "";

            if (string.IsNullOrEmpty(letter) || string.IsNullOrEmpty(share))
            {
                MessageBox.Show("Select both drive letter and share name");
                return;
            }

            drives.Add(new DriveMapping { DriveLetter = letter, ShareName = share, Status = "Disconnected" });
            RefreshStatus();
            
            // Refresh available drive letters
            PopulateAvailableDriveLetters();
            
            SaveCurrentSettings();
        }

        private void RemoveDriveButton_Click(object sender, EventArgs e)
        {
            if (drivesGrid.SelectedRows.Count > 0)
            {
                int index = drivesGrid.SelectedRows[0].Index;
                drives.RemoveAt(index);
                RefreshStatus();
                SaveCurrentSettings();
            }
        }

        private void ConnectButton_Click(object sender, EventArgs e)
        {
            // Check if Tailscale is connected first
            if (!IsTailscaleConnected())
            {
                MessageBox.Show("Tailscale is not connected. Please enable Tailscale first.", "Tailscale Required");
                statusLabel.Text = "Error: Tailscale not connected";
                return;
            }

            string username = usernameBox.Text;
            string password = passwordBox.Text;

            if (string.IsNullOrEmpty(username) || string.IsNullOrEmpty(password))
            {
                MessageBox.Show("Enter username and password");
                return;
            }

            foreach (var drive in drives)
            {
                try
                {
                    // Ensure drive letter has colon
                    string driveLetter = drive.DriveLetter.EndsWith(":") ? drive.DriveLetter : drive.DriveLetter + ":";
                    string cmd = $"net use {driveLetter} \\\\{fileserverIP}\\{drive.ShareName} {password} /user:{username} /persistent:yes";
                    ExecuteCommand(cmd);
                    drive.Status = "Connected";
                    Log($"Connected {driveLetter} to {drive.ShareName}");
                }
                catch (Exception ex)
                {
                    drive.Status = "Error";
                    Log($"Failed to connect {drive.DriveLetter}: - {ex.Message}");
                }
            }
            RefreshStatus();
        }

        private void DisconnectButton_Click(object sender, EventArgs e)
        {
            foreach (var drive in drives)
            {
                try
                {
                    // Ensure drive letter has colon
                    string driveLetter = drive.DriveLetter.EndsWith(":") ? drive.DriveLetter : drive.DriveLetter + ":";
                    ExecuteCommand($"net use {driveLetter} /delete /yes");
                    drive.Status = "Disconnected";
                    Log($"Disconnected {driveLetter}");
                }
                catch (Exception ex)
                {
                    Log($"Failed to disconnect {drive.DriveLetter}: - {ex.Message}");
                }
            }
            RefreshStatus();
        }

