        private void RefreshStatus()
        {
            // Don't update status if currently authenticating
            if (isAuthenticating)
                return;
            
            // Update actual drive connection status before displaying
            foreach (var drive in drives)
            {
                drive.Status = IsDriveMounted(drive.DriveLetter) ? "Connected" : "Disconnected";
            }
            
            drivesGrid.DataSource = null;
            drivesGrid.DataSource = new List<DriveMapping>(drives);
            
            // Disable Mount Drives button if all drives are already connected
            if (drives.Count > 0)
            {
                bool allConnected = drives.All(d => d.Status == "Connected");
                connectButton.Enabled = !allConnected;
                connectButton.BackColor = allConnected ? Color.FromArgb(150, 150, 150) : Color.FromArgb(21, 101, 200);
            }
            
            statusLabel.Text = "Ready";
        }

        private bool IsDriveMounted(string driveLetter)
        {
            try
            {
                // Ensure drive letter has colon
                string letter = driveLetter.EndsWith(":") ? driveLetter : driveLetter + ":";
                
                // Try to access the drive
                DriveInfo driveInfo = new DriveInfo(letter);
                return driveInfo.IsReady;
            }
            catch
            {
                return false;
            }
        }

        private bool IsTailscaleConnected()
        {
            try
            {
                // Run tailscale status to check for IP
                ProcessStartInfo psi = new ProcessStartInfo("tailscale.exe", "status")
                {
                    UseShellExecute = false,
                    RedirectStandardOutput = true,
                    CreateNoWindow = true
                };
                
                using (Process p = Process.Start(psi))
                {
                    string output = p.StandardOutput.ReadToEnd();
                    p.WaitForExit();
                    
                    // Check if output contains a 100.x.x.x IP (Tailscale IP range)
                    return output.Contains("100.") && output.Contains("ok");
                }
            }
            catch
            {
                return false;
            }
        }

        private void ExecuteCommand(string command)
        {
            ProcessStartInfo psi = new ProcessStartInfo("cmd.exe", "/c " + command) 
            { 
                UseShellExecute = false, 
                RedirectStandardOutput = true, 
                RedirectStandardError = true,
                CreateNoWindow = true 
            };
            using (Process p = Process.Start(psi))
            {
                string output = p.StandardOutput.ReadToEnd();
                string error = p.StandardError.ReadToEnd();
                p.WaitForExit();
                
                if (p.ExitCode != 0)
                {
                    string errorMsg = !string.IsNullOrEmpty(error) ? error : output;
                    throw new Exception(errorMsg);
                }
            }
        }

        private string EncryptPassword(string password)
        {
            try
            {
                byte[] key = System.Text.Encoding.UTF8.GetBytes("FileserverDM2026");  // 16 bytes key
                using (Aes aes = Aes.Create())
                {
                    aes.Key = key;
                    aes.Mode = CipherMode.CBC;
                    aes.Padding = PaddingMode.PKCS7;

                    using (var encryptor = aes.CreateEncryptor(aes.Key, aes.IV))
                    {
                        using (MemoryStream ms = new MemoryStream())
                        {
                            ms.Write(aes.IV, 0, aes.IV.Length);
                            using (CryptoStream cs = new CryptoStream(ms, encryptor, CryptoStreamMode.Write))
                            {
                                using (StreamWriter sw = new StreamWriter(cs))
                                {
                                    sw.Write(password);
                                }
                                return Convert.ToBase64String(ms.ToArray());
                            }
                        }
                    }
                }
            }
            catch
            {
                return password;  // Fallback to plain text
            }
        }

        private string DecryptPassword(string encryptedPassword)
        {
            try
            {
                byte[] key = System.Text.Encoding.UTF8.GetBytes("FileserverDM2026");
                byte[] buffer = Convert.FromBase64String(encryptedPassword);
                
                using (Aes aes = Aes.Create())
                {
                    aes.Key = key;
                    aes.Mode = CipherMode.CBC;
                    aes.Padding = PaddingMode.PKCS7;

                    byte[] iv = new byte[aes.IV.Length];
                    Array.Copy(buffer, 0, iv, 0, iv.Length);
                    aes.IV = iv;

                    using (var decryptor = aes.CreateDecryptor(aes.Key, aes.IV))
                    {
                        using (MemoryStream ms = new MemoryStream(buffer, iv.Length, buffer.Length - iv.Length))
                        {
                            using (CryptoStream cs = new CryptoStream(ms, decryptor, CryptoStreamMode.Read))
                            {
                                using (StreamReader sr = new StreamReader(cs))
                                {
                                    return sr.ReadToEnd();
                                }
                            }
                        }
                    }
                }
            }
            catch
            {
                return encryptedPassword;  // Fallback to plain text
            }
        }

        private void SaveCurrentSettings()
        {
            try
            {
                string settingsPath = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData), "FileserverDriveManager-settings.json");
                
                Dictionary<string, object> settings = new Dictionary<string, object>();
                
                // Save username and password (encrypt password)
                settings["username"] = usernameBox.Text;
                settings["password"] = EncryptPassword(passwordBox.Text);
                
                // Save drives list
                List<Dictionary<string, string>> drivesList = new List<Dictionary<string, string>>();
                foreach (var drive in drives)
                {
                    drivesList.Add(new Dictionary<string, string>
                    {
                        { "letter", drive.DriveLetter },
                        { "share", drive.ShareName }
                    });
                }
                settings["drives"] = drivesList;
                
                // Save Tailscale state
                settings["tailscale_enabled"] = true;
                settings["tailscale_connected_at"] = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");
                
                string json = System.Text.Json.JsonSerializer.Serialize(settings, new System.Text.Json.JsonSerializerOptions { WriteIndented = true });
                File.WriteAllText(settingsPath, json);
                
                Log("Settings saved");
            }
            catch (Exception ex)
            {
                Log("Error saving settings: " + ex.Message);
            }
        }

        private void LoadSavedSettings()
        {
            try
            {
                string settingsPath = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData), "FileserverDriveManager-settings.json");
                Log($"Attempting to load settings from: {settingsPath}");
                
                if (File.Exists(settingsPath))
                {
                    Log("Settings file found");
                    string json = File.ReadAllText(settingsPath);
                    Log($"Settings JSON length: {json.Length} characters");
                    
                    var settings = System.Text.Json.JsonSerializer.Deserialize<Dictionary<string, System.Text.Json.JsonElement>>(json);
                    
                    if (settings != null)
                    {
                        Log($"Settings deserialized successfully, contains {settings.Count} keys");
                        
                        // Load username
                        if (settings.ContainsKey("username"))
                        {
                            string username = settings["username"].GetString() ?? "";
                            usernameBox.Text = username;
                            Log($"Loaded username: {username}");
                        }
                        else
                        {
                            Log("No 'username' key in settings");
                        }
                        
                        // Load password
                        if (settings.ContainsKey("password"))
                        {
                            string encryptedPassword = settings["password"].GetString() ?? "";
                            string decryptedPassword = DecryptPassword(encryptedPassword);
                            passwordBox.Text = decryptedPassword;
                            Log($"Loaded password: {'*' + new string('*', decryptedPassword.Length - 1)}");
                        }
                        else
                        {
                            Log("No 'password' key in settings");
                        }
                        
                        // Load drives
                        if (settings.ContainsKey("drives"))
                        {
                            Log("Found 'drives' key in settings");
                            var drivesList = System.Text.Json.JsonSerializer.Deserialize<List<Dictionary<string, string>>>(settings["drives"].GetRawText());
                            if (drivesList != null)
                            {
                                Log($"Deserialized {drivesList.Count} drives");
                                foreach (var driveDict in drivesList)
                                {
                                    if (driveDict.ContainsKey("letter") && driveDict.ContainsKey("share"))
                                    {
                                        drives.Add(new DriveMapping { DriveLetter = driveDict["letter"], ShareName = driveDict["share"], Status = "Disconnected" });
                                        Log($"Added drive: {driveDict["letter"]} -> {driveDict["share"]}");
                                    }
                                }
                            }
                            else
                            {
                                Log("Failed to deserialize drives list");
                            }
                        }
                        else
                        {
                            Log("No 'drives' key in settings");
                        }
                        
                        // Check for Tailscale settings
                        if (settings.ContainsKey("tailscale_enabled"))
                        {
                            bool enabled = settings["tailscale_enabled"].GetBoolean();
                            Log($"Tailscale enabled: {enabled}");
                            if (enabled)
                            {
                                Log("Tailscale was previously connected - attempting to reconnect");
                                // Auto-connect Tailscale on startup
                                this.Load += (s, e) =>
                                {
                                    try
                                    {
                                        Process p = new Process();
                                        p.StartInfo.FileName = "C:\\Program Files\\Tailscale\\tailscale.exe";
                                        p.StartInfo.Arguments = "up";
                                        p.StartInfo.UseShellExecute = false;
                                        p.StartInfo.CreateNoWindow = true;
                                        p.Start();
                                        Log("Tailscale auto-connect initiated on startup");
                                    }
                                    catch (Exception ex)
                                    {
                                        Log("Error auto-connecting Tailscale: " + ex.Message);
                                    }
                                };
                            }
                        }
                        else
                        {
                            Log("No 'tailscale_enabled' key in settings");
                        }
                    }
                    else
                    {
                        Log("Failed to deserialize settings JSON");
                    }
                    
                    Log("Settings loaded");
                }
                else
                {
                    Log($"Settings file does not exist at: {settingsPath}");
                }
            }
            catch (Exception ex)
            {
                Log($"Error loading settings: {ex.Message}\n{ex.StackTrace}");
            }
        }

        private void Log(string message)
        {
            try
            {
                string entry = $"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] {message}";
                File.AppendAllText(logPath, entry + Environment.NewLine);
            }
            catch { }
        }

        private void AutoMapButton_Click(object sender, EventArgs e)
        {
            try
            {
                if (drives.Count == 0)
                {
                    statusLabel.Text = "Add at least one drive first";
                    return;
                }

                if (string.IsNullOrEmpty(usernameBox.Text) || string.IsNullOrEmpty(passwordBox.Text))
                {
                    statusLabel.Text = "Enter username and password";
                    return;
                }

                string appDir = AppDomain.CurrentDomain.BaseDirectory;
                string configPath = Path.Combine(appDir, "drive-config.json");
                string scriptPath = Path.Combine(appDir, "AutoMapDrives.ps1");

                // Create the PowerShell script if it doesn't exist
                CreatePowerShellScript(scriptPath);

                // Save config to JSON
                var config = new
                {
                    fileserver = "192.168.1.26",
                    username = usernameBox.Text,
                    password = passwordBox.Text,
                    drives = drives.Select(d => new { letter = d.DriveLetter, share = d.ShareName }).ToList()
                };

                string json = System.Text.Json.JsonSerializer.Serialize(config, new System.Text.Json.JsonSerializerOptions { WriteIndented = true });
                File.WriteAllText(configPath, json);

                // Create Windows Task Scheduler task
                CreateScheduledTask(scriptPath);

                statusLabel.Text = "Auto-Map enabled! Drives will auto-connect when Tailscale is online";
                Log("Auto-Map enabled with " + drives.Count + " drives");
                MessageBox.Show("Auto-Map has been enabled!\\n\\nDrives will automatically map when Tailscale connects.", "Success");
            }
            catch (Exception ex)
            {
                statusLabel.Text = "Error enabling Auto-Map: " + ex.Message;
                Log("Error enabling Auto-Map: " + ex.Message);
                MessageBox.Show("Error: " + ex.Message, "Error");
            }
        }

        private void CreatePowerShellScript(string scriptPath)
        {
            string script = @"# AutoMapDrives.ps1
# Automated SMB Drive Mapping Script
# Triggered when Tailscale connects or on schedule

param(
    [string]$ConfigFile = ""C:\FileserverDriveManager\drive-config.json"",
    [string]$LogFile = ""$env:APPDATA\FileserverDriveManager-AutoMap.log""
)

function Write-Log {
    param([string]$Message, [string]$Level = ""INFO"")
    $timestamp = Get-Date -Format ""yyyy-MM-dd HH:mm:ss""
    $logEntry = ""[$timestamp] [$Level] $Message""
    Add-Content -Path $LogFile -Value $logEntry
    Write-Host $logEntry
}

function Test-TailscaleConnected {
    try {
        $status = & ""C:\Program Files\Tailscale\tailscale.exe"" status --json | ConvertFrom-Json
        return $status.IsRunning -and $status.IsSynced
    }
    catch {
        Write-Log ""Error checking Tailscale status: $_"" ""ERROR""
        return $false
    }
}

function Load-DriveConfig {
    if (-not (Test-Path $ConfigFile)) {
        Write-Log ""Config file not found: $ConfigFile"" ""ERROR""
        return $null
    }
    
    try {
        $config = Get-Content $ConfigFile | ConvertFrom-Json
        Write-Log ""Loaded configuration for $($config.drives.Count) drives""
        return $config
    }
    catch {
        Write-Log ""Error loading config: $_"" ""ERROR""
        return $null
    }
}

function Map-NetworkDrive {
    param(
        [string]$DriveLetter,
        [string]$SharePath,
        [string]$Username,
        [string]$Password
    )
    
    try {
        $drive = Get-PSDrive -Name $DriveLetter -ErrorAction SilentlyContinue
        if ($drive) {
            Write-Log ""Drive $($DriveLetter): already mapped""
            return $true
        }
        
        $securePassword = ConvertTo-SecureString $Password -AsPlainText -Force
        $credential = New-Object System.Management.Automation.PSCredential($Username, $securePassword)
        New-PSDrive -Name $DriveLetter -PSProvider FileSystem -Root ""\\192.168.1.26\$SharePath"" -Credential $credential -Persist | Out-Null
        
        Write-Log ""Successfully mapped $($DriveLetter): to \\192.168.1.26\$SharePath""
        return $true
    }
    catch {
        Write-Log ""Error mapping $($DriveLetter):: $_"" ""ERROR""
        return $false
    }
}

function Main {
    Write-Log ""=== AutoMapDrives Started ===""
    
    if (-not (Test-TailscaleConnected)) {
        Write-Log ""Tailscale not connected. Skipping drive mapping."" ""WARN""
        return
    }
    
    Write-Log ""Tailscale is connected""
    
    $config = Load-DriveConfig
    if (-not $config) {
        Write-Log ""Failed to load configuration"" ""ERROR""
        return
    }
    
    $successCount = 0
    $failCount = 0
    
    foreach ($drive in $config.drives) {
        if (Map-NetworkDrive -DriveLetter $drive.letter -SharePath $drive.share -Username $config.username -Password $config.password) {
            $successCount++
        }
        else {
            $failCount++
        }
        
        Start-Sleep -Milliseconds 500
    }
    
    Write-Log ""=== AutoMapDrives Complete: $successCount success, $failCount failed ===""
}

Main
";
            File.WriteAllText(scriptPath, script);
            Log("PowerShell script created: " + scriptPath);
        }

        private void TailscaleButton_Click(object sender, EventArgs e)
        {
