                p.StartInfo.Arguments = "up";
                p.StartInfo.UseShellExecute = false;
                p.StartInfo.CreateNoWindow = true;
                p.StartInfo.RedirectStandardOutput = true;
                p.Start();
                p.WaitForExit();
                
                // Save connection attempt to settings
                SaveTailscaleConnectionState();
                
                statusLabel.Text = "Tailscale connect initiated - check tray app";
                Log("Tailscale up command executed");
                
                // Try to bring Tailscale tray app to focus
                try
                {
                    Process.Start(new ProcessStartInfo
                    {
                        FileName = "C:\\Program Files\\Tailscale\\Tailscale.exe",
                        UseShellExecute = true
                    });
                }
                catch { }
            }
            catch (Exception ex)
            {
                statusLabel.Text = "Error with Tailscale";
                Log("Tailscale error: " + ex.Message);
                MessageBox.Show("Could not execute Tailscale. Make sure it's installed and the tray app is running.", "Error");
            }
        }

        private void SaveTailscaleConnectionState()
        {
            try
            {
                string settingsPath = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData), "FileserverDriveManager-settings.json");
                
                // Read existing settings
                Dictionary<string, object> settings = new Dictionary<string, object>();
                if (File.Exists(settingsPath))
                {
                    try
                    {
                        string json = File.ReadAllText(settingsPath);
                        settings = System.Text.Json.JsonSerializer.Deserialize<Dictionary<string, object>>(json) ?? new Dictionary<string, object>();
                    }
                    catch { }
                }
                
                // Add/update Tailscale connection timestamp
                settings["tailscale_connected_at"] = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");
                settings["tailscale_enabled"] = true;
                
                // Save back
                string updatedJson = System.Text.Json.JsonSerializer.Serialize(settings, new System.Text.Json.JsonSerializerOptions { WriteIndented = true });
                File.WriteAllText(settingsPath, updatedJson);
                
                Log("Tailscale connection state saved");
            }
            catch (Exception ex)
            {
                Log("Error saving Tailscale state: " + ex.Message);
            }
        }

        private void CreateScheduledTask(string scriptPath)
        {
            string taskName = "FileserverAutoMapDrives";

            // Remove existing task if it exists
            try
            {
                Process.Start(new ProcessStartInfo
                {
                    FileName = "schtasks.exe",
                    Arguments = $"/delete /tn \"{taskName}\" /f",
                    UseShellExecute = false,
                    CreateNoWindow = true
                }).WaitForExit();
            }
            catch { }

            // Create new task - runs every 5 minutes to ensure drives stay mapped
            string argument = $"/create /tn \"{taskName}\" /tr \"powershell.exe -ExecutionPolicy Bypass -File '{scriptPath}'\" /sc minute /mo 5 /f";

            Process.Start(new ProcessStartInfo
            {
                FileName = "schtasks.exe",
                Arguments = argument,
                UseShellExecute = false,
                CreateNoWindow = true
            }).WaitForExit();

            Log("Scheduled task created: " + taskName);
        }

        private void UpdateTailscaleIP()
        {
            try
            {
                // Run tailscale status to get IP
                Process p = new Process();
                p.StartInfo.FileName = "C:\\Program Files\\Tailscale\\tailscale.exe";
                p.StartInfo.Arguments = "status";
                p.StartInfo.UseShellExecute = false;
                p.StartInfo.RedirectStandardOutput = true;
                p.StartInfo.RedirectStandardError = true;
                p.StartInfo.CreateNoWindow = true;
                p.Start();
                
                string output = p.StandardOutput.ReadToEnd();
                p.WaitForExit();
                
                string tailscaleIP = "Not Connected";
                
                // Look for any line with 100. (Tailscale IP range)
                if (output.Contains("100."))
                {
                    string[] lines = output.Split('\n');
                    foreach (string line in lines)
                    {
                        if (line.Contains("100."))
                        {
                            // Extract the IP - find first 100.x.x.x pattern
                            int idx = line.IndexOf("100.");
                            if (idx >= 0)
                            {
                                string potential = line.Substring(idx);
                                // Get just the IP part (stop at space, bracket, or end)
                                int endIdx = 0;
                                for (int i = 0; i < potential.Length; i++)
                                {
                                    if (char.IsDigit(potential[i]) || potential[i] == '.')
                                    {
                                        endIdx = i + 1;
                                    }
                                    else
                                    {
                                        break;
                                    }
                                }
                                if (endIdx > 0)
                                {
                                    tailscaleIP = potential.Substring(0, endIdx);
                                    break;
                                }
                            }
                        }
                    }
                }
                
                // Update the label on UI thread
                if (tailscaleIPLabel != null && tailscaleIPLabel.InvokeRequired)
                {
                    tailscaleIPLabel.Invoke(new Action(() =>
                    {
                        tailscaleIPLabel.Text = $"Tailscale IP: {tailscaleIP}";
                        tailscaleIPLabel.ForeColor = (tailscaleIP != "Not Connected") ? Color.Green : Color.Gray;
                        
                        // Enable Mount Drives button when Tailscale is connected
                        bool isConnected = tailscaleIP != "Not Connected";
                        if (connectButton != null)
                        {
                            connectButton.Enabled = isConnected;
                            connectButton.BackColor = isConnected ? Color.FromArgb(21, 101, 200) : Color.FromArgb(150, 150, 150);
                        }
                        
                        // If connected, reset status to Ready and disable button
                        if (tailscaleIP != "Not Connected")
                        {
                            statusLabel.Text = "Ready";
                            if (tailscaleButton != null)
                            {
                                tailscaleButton.Enabled = false;
                                tailscaleButton.BackColor = Color.FromArgb(200, 200, 200);
                                tailscaleButton.ForeColor = Color.FromArgb(100, 100, 100);
                            }
                        }
                        else
                        {
                            // If disconnected, re-enable button
                            if (tailscaleButton != null)
                            {
                                tailscaleButton.Enabled = true;
                                tailscaleButton.BackColor = Color.FromArgb(240, 240, 240);
                                tailscaleButton.ForeColor = Color.Black;
                            }
                        }
                    }));
                }
                else if (tailscaleIPLabel != null)
                {
                    tailscaleIPLabel.Text = $"Tailscale IP: {tailscaleIP}";
                    tailscaleIPLabel.ForeColor = (tailscaleIP != "Not Connected") ? Color.Green : Color.Gray;
                    
                    // If connected, reset status to Ready and disable button
                    if (tailscaleIP != "Not Connected")
                    {
                        statusLabel.Text = "Ready";
                        if (tailscaleButton != null)
                        {
                            tailscaleButton.Enabled = false;
                            tailscaleButton.BackColor = Color.FromArgb(200, 200, 200);
                            tailscaleButton.ForeColor = Color.FromArgb(100, 100, 100);
                        }
                    }
                    else
                    {
                        // If disconnected, re-enable button
                        if (tailscaleButton != null)
                        {
                            tailscaleButton.Enabled = true;
                            tailscaleButton.BackColor = Color.FromArgb(240, 240, 240);
                            tailscaleButton.ForeColor = Color.Black;
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Log("Error updating Tailscale IP: " + ex.Message);
            }
        }
    }

