    // Logo click handler to replace logo
    partial class MainForm
    {
        private void LogoPicture_Click(object sender, EventArgs e)
        {
            using (OpenFileDialog ofd = new OpenFileDialog())
            {
                ofd.Title = "Select New Logo Image";
                ofd.Filter = "Image Files (*.png;*.jpg;*.jpeg;*.bmp)|*.png;*.jpg;*.jpeg;*.bmp|All Files (*.*)|*.*";
                ofd.InitialDirectory = Path.GetDirectoryName(System.Reflection.Assembly.GetExecutingAssembly().Location);
                
                if (ofd.ShowDialog() == DialogResult.OK)
                {
                    try
                    {
                        string appDir = Path.GetDirectoryName(System.Reflection.Assembly.GetExecutingAssembly().Location);
                        string logoPath = Path.Combine(appDir, "logo.png");
                        
                        // Read selected file into memory as byte array
                        byte[] imageData = File.ReadAllBytes(ofd.FileName);
                        
                        // Create bitmap from memory stream (no file lock)
                        Bitmap newLogo;
                        using (MemoryStream ms = new MemoryStream(imageData))
                        {
                            newLogo = new Bitmap(ms);
                        }
                        
                        // Dispose old logo to release the lock
                        if (logoPicture.Image != null)
                        {
                            logoPicture.Image.Dispose();
                        }
                        
                        // Delete old logo.png if it exists
                        if (File.Exists(logoPath))
                        {
                            try { File.Delete(logoPath); }
                            catch { }
                        }
                        
                        // Write image data to logo.png
                        File.WriteAllBytes(logoPath, imageData);
                        
                        // Set new logo
                        logoPicture.Image = newLogo;
                        
                        statusLabel.Text = "Logo updated successfully";
                        Log("Logo replaced from: " + ofd.FileName);
                    }
                    catch (Exception ex)
                    {
                        MessageBox.Show("Error replacing logo: " + ex.Message, "Error");
                        Log("Logo replacement error: " + ex.Message);
                    }
                }
            }
        }

        private void FaviconButton_Click(object sender, EventArgs e)
        {
            using (OpenFileDialog ofd = new OpenFileDialog())
            {
                ofd.Title = "Select New Window Icon";
                ofd.Filter = "Image Files (*.png;*.jpg;*.jpeg;*.ico;*.bmp)|*.png;*.jpg;*.jpeg;*.ico;*.bmp|All Files (*.*)|*.*";
                ofd.InitialDirectory = Path.GetDirectoryName(System.Reflection.Assembly.GetExecutingAssembly().Location);
                
                if (ofd.ShowDialog() == DialogResult.OK)
                {
                    try
                    {
                        string appDir = Path.GetDirectoryName(System.Reflection.Assembly.GetExecutingAssembly().Location);
                        string iconPath = Path.Combine(appDir, "icon.png");
                        
                        // Read selected file into memory as byte array
                        byte[] imageData = File.ReadAllBytes(ofd.FileName);
                        
                        // Create icon from memory stream (no file lock)
                        Icon newIcon = null;
                        using (MemoryStream ms = new MemoryStream(imageData))
                        {
                            using (Bitmap bmp = new Bitmap(ms))
                            {
                                newIcon = Icon.FromHandle(bmp.GetHicon());
                            }
                        }
                        
                        // Dispose old icon to release the lock
                        if (this.Icon != null)
                        {
                            this.Icon.Dispose();
                        }
                        
                        // Delete old icon.png if it exists
                        if (File.Exists(iconPath))
                        {
                            try { File.Delete(iconPath); }
                            catch { }
                        }
                        
                        // Write image data to icon.png
                        File.WriteAllBytes(iconPath, imageData);
                        
                        // Set new icon
                        this.Icon = newIcon;
                        notifyIcon.Icon = this.Icon ?? SystemIcons.Application;
                        
                        statusLabel.Text = "Window icon updated successfully";
                        Log("Icon replaced from: " + ofd.FileName);
                    }
                    catch (Exception ex)
                    {
                        MessageBox.Show("Error replacing icon: " + ex.Message, "Error");
                        Log("Icon replacement error: " + ex.Message);
                    }
                }
            }
        }
    }
